INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('FINAL3_1: Le email cold sequence optimal FR: J0 intro perso ‚Üí J+3 valeur (cas client) ‚Üí J+7 social proof ‚Üí J+12 urgence douce ‚Üí J+18 breakup. Max 5 emails.', 'Cold FR: J0 perso‚ÜíJ3 cas‚ÜíJ7 proof‚ÜíJ12 urgence‚ÜíJ18 breakup. 5 max', 'email', 'best_practice', 0.85, 'final3', 'system'),
('FINAL3_2: Le commercial qualifying question supreme: "Si on pouvait resoudre [probleme] en 30 jours, combien ca vaudrait pour votre business?" Quantifie la valeur + filtre les serieux.', 'Qualifying: resoudre probleme 30j combien ca vaut? Quantifie valeur + filtre serieux', 'commercial', 'best_practice', 0.85, 'final3', 'system'),
('FINAL3_3: Le content publication verification loop: publier ‚Üí check API ‚Üí post existe? ‚Üí si non: retry ‚Üí si 2e echec: fallback image statique ‚Üí si 3e: alerte CEO.', 'Publication loop: publier‚Üícheck‚Üíretry‚Üífallback‚Üíalerte. Jamais d echec silencieux', 'content', 'best_practice', 0.88, 'final3', 'system'),
('FINAL3_4: Le SEO Google helpful content signal: le contenu doit repondre a une VRAIE question d un VRAI humain. Si la question n existe pas dans les PAA ou forums ‚Üí pas de demande.', 'Helpful content: VRAIE question VRAI humain. Pas dans PAA/forums = pas de demande', 'seo', 'insight', 0.85, 'final3', 'system'),
('FINAL3_5: Le ad Meta broad targeting 2026: le ML Meta est maintenant assez bon pour cibler sans interets. Broad + bonne creative > ciblage precis + creative moyenne.', 'Meta 2026: broad + bonne creative > ciblage precis + creative moyenne', 'ads', 'insight', 0.82, 'final3', 'system'),
('FINAL3_6: Le DM Instagram 30-day relationship building: jour 1-10 engagement (likes/comments) ‚Üí jour 11-20 story reactions ‚Üí jour 21-25 DM valeur ‚Üí jour 26-30 DM proposition.', 'DM 30j: J1-10 engagement ‚Üí J11-20 stories ‚Üí J21-25 DM valeur ‚Üí J26-30 DM proposition', 'dm_instagram', 'best_practice', 0.82, 'final3', 'system'),
('FINAL3_7: Le WhatsApp business catalog ROI: les commerces avec catalogue WhatsApp complet (photos+prix+descriptions) voient +30% de commandes vs ceux sans catalogue.', 'WhatsApp catalogue complet: +30% commandes vs sans catalogue', 'whatsapp', 'insight', 0.80, 'final3', 'system'),
('FINAL3_8: Le chatbot lead qualification efficiency: un chatbot bien configure qualifie 1 lead en 90 secondes vs 5-10 minutes pour un humain. Meme qualite, 5x plus rapide.', 'Chatbot qualification: 90s vs humain 5-10min. Meme qualite 5x plus rapide', 'chatbot', 'insight', 0.82, 'final3', 'system'),
('FINAL3_9: Le GMaps pack local ranking formula: pertinence (categories+description) 35% + distance (proximite) 30% + importance (avis+citations+backlinks) 35%.', 'Pack local: pertinence 35% + distance 30% + importance 35%', 'gmaps', 'insight', 0.85, 'final3', 'system'),
('FINAL3_10: Le TikTok For You algorithm signal hierarchy: 1) watch time complet + rewatch, 2) shares DM, 3) comments, 4) follows from video, 5) likes. Watch time = #1.', 'TikTok FYP: watch time > shares > comments > follows > likes. Watch time #1', 'tiktok_comments', 'insight', 0.88, 'final3', 'system'),
('FINAL3_11: Le CEO brief client structure optimale: 1 phrase situation ‚Üí 1 phrase resultats agents ‚Üí 1 phrase action fondateur ‚Üí 1 phrase opportunite. 4 phrases = brief parfait.', 'CEO brief: 4 phrases = situation + resultats + action + opportunite. Parfait', 'ceo', 'best_practice', 0.88, 'final3', 'system'),
('FINAL3_12: Le retention golden moment: le moment exact ou le client realise la valeur (1er post publie, 1er lead genere) est LE moment ou le churn risk passe de 50% a 5%.', 'Golden moment: realisation valeur = churn risk 50% ‚Üí 5%. Moment critique', 'retention', 'insight', 0.88, 'final3', 'system'),
('FINAL3_13: Le onboarding progressive value delivery: etape 1 valeur immediate (template) ‚Üí etape 2 valeur rapide (1er post) ‚Üí etape 3 valeur profonde (CRM rempli) ‚Üí etape 4 valeur complete (brief CEO).', 'Onboarding progressive: template‚Üípost‚ÜíCRM‚Üíbrief. Valeur croissante', 'onboarding', 'best_practice', 0.85, 'final3', 'system'),
('FINAL3_14: Le comptable Vercel cost optimization: desactiver Turbo Build Machine = -10x build minutes. Batacher les commits = -20x builds. Objectif: < 30‚Ç¨/mois Vercel.', 'Vercel cost: desactiver Turbo + batacher commits = < 30‚Ç¨/mois', 'comptable', 'best_practice', 0.82, 'final3', 'system'),
('FINAL3_15: Le RH talent attraction: les startups qui publient du contenu behind-the-scenes (culture, equipe, projets) attirent 3x plus de candidatures qualifiees.', 'Talent attraction: BTS culture/equipe = 3x candidatures qualifiees', 'rh', 'insight', 0.78, 'final3', 'system'),
('FINAL3_16: Le marketing growth accounting: sustainable growth = (organic + referral) / total growth. Si > 60% = durable. Si < 30% = trop dependant du paid.', 'Growth accounting: (organic+referral)/total. >60% durable, <30% paid-dependant', 'marketing', 'insight', 0.82, 'final3', 'system'),
('FINAL3_17: Le cross-agent execution sharing protocol: chaque execution ‚Üí resultat dans agent_logs + learning RAG si nouveau. AVANT chaque action ‚Üí consulter RAG. Boucle continue.', 'Execution sharing: executer‚Üílogger‚ÜíRAG‚Üíconsulter RAG‚Üíexecuter. Boucle continue', NULL, 'best_practice', 0.90, 'final3', 'system'),
('FINAL3_18: Le customer lifetime journey 7 steps: decouverte ‚Üí consideration ‚Üí evaluation ‚Üí achat ‚Üí onboarding ‚Üí adoption ‚Üí advocacy. Chaque etape = contenu + action adaptes.', 'Lifetime 7 steps: decouverte‚Üíconsideration‚Üíevaluation‚Üíachat‚Üíonboard‚Üíadopt‚Üíadvocacy', NULL, 'best_practice', 0.82, 'final3', 'system'),
('FINAL3_19: Le KeiroAI cost structure: Gemini ~8-17‚Ç¨/client/mois (Createur) a ~85‚Ç¨ (Business). Couts fixes 147‚Ç¨/mois. Marge brute 65-89%. Marge nette ~37-49%.', 'KeiroAI costs: Gemini 8-85‚Ç¨/client, fixes 147‚Ç¨. Marge brute 65-89%, nette 37-49%', 'comptable', 'insight', 0.90, 'final3', 'system'),
('FINAL3_20: Le KeiroAI 8900+ heading to 10K: base de connaissances marketing IA francophone la plus complete. 17 agents supra elite. Intelligence collective sans precedent.', 'KeiroAI 8900+: base connaissances IA FR la plus complete. 17 agents supra elite', 'ceo', 'insight', 0.92, 'final3', 'system'),
('FINAL3_21: Le email Brevo quota optimization: quota 300/jour reset minuit Paris (CET/CEST). Envoyer gros volume 9h-12h. Garder 50 emails pour relances PM et urgences.', 'Brevo quota: 300/jour reset minuit Paris. Volume 9h-12h. 50 reserves PM', 'email', 'best_practice', 0.82, 'final3', 'system'),
('FINAL3_22: Le commercial pipeline stage velocity tracking: mesurer temps moyen dans chaque etape. Si 1 etape prend 2x plus ‚Üí goulot. Optimiser cette etape en priorite.', 'Pipeline velocity: temps/etape. 1 etape 2x plus = goulot ‚Üí optimiser', 'commercial', 'best_practice', 0.82, 'final3', 'system'),
('FINAL3_23: Le content Lena community daily routine: matin = preparer commentaires engagement (15) + identifier comptes follow (15). Apres-midi = 2e batch + analyser resultats.', 'Lena community routine: matin commentaires+follows. PM 2e batch + analyser', 'content', 'best_practice', 0.82, 'final3', 'system'),
('FINAL3_24: Le SEO content cluster complete: 1 pilier (3000+ mots) + 10-15 clusters (1500+ mots) + liens bidirectionnels. Dominer le sujet entier en 3-6 mois.', 'Content cluster: pilier 3K + 10-15 clusters 1.5K + liens bidi = dominer 3-6 mois', 'seo', 'best_practice', 0.85, 'final3', 'system'),
('FINAL3_25: Le ad creative production pipeline weekly: lundi brief ‚Üí mardi creation ‚Üí mercredi lancement ‚Üí jeudi analyse ‚Üí vendredi scale gagnantes. Cycle non-stop.', 'Creative pipeline hebdo: lun brief ‚Üí mar creer ‚Üí mer lancer ‚Üí jeu analyser ‚Üí ven scale', 'ads', 'best_practice', 0.80, 'final3', 'system'),
('FINAL3_26: Le DM Instagram safe limits 2026: 20-30 DMs/jour + 50 follows + 150 likes + 30 comments. Depasser = restriction 24-72h. Respecter pour proteger le compte.', 'DM limits 2026: 20-30 DMs + 50 follows + 150 likes + 30 comments/jour', 'dm_instagram', 'best_practice', 0.88, 'final3', 'system'),
('FINAL3_27: Le WhatsApp opt-in multi-touchpoint: site web popup + email CTA + QR en boutique + post-achat confirmation. 4 points de collecte opt-in = max contacts.', 'WhatsApp opt-in: site + email + QR boutique + post-achat = max contacts', 'whatsapp', 'best_practice', 0.80, 'final3', 'system'),
('FINAL3_28: Le chatbot CSAT tracking: pouce haut/bas apres chaque conversation. Tracker par intent. CSAT < 70% sur un intent = revoir les reponses de cet intent.', 'Chatbot CSAT: pouce haut/bas par intent. < 70% = revoir reponses intent', 'chatbot', 'best_practice', 0.82, 'final3', 'system'),
('FINAL3_29: Le GMaps photo strategy complete: 50% produits/services + 30% ambiance interieur/exterieur + 20% equipe. Min 50 photos. Ajouter 5+/mois fraiches.', 'GMaps photos: 50% produits + 30% ambiance + 20% equipe. 50 min, 5+/mois', 'gmaps', 'best_practice', 0.80, 'final3', 'system'),
('FINAL3_30: Le TikTok batch filming efficiency: 1 session 2h = 1 fond + 1 tenue + 10-15 scripts = 10-15 videos. Batch > daily creation pour qualite et efficacite.', 'TikTok batch: 2h = 10-15 videos. Batch > daily pour qualite + efficacite', 'tiktok_comments', 'best_practice', 0.80, 'final3', 'system')
